Xoá ứng dụng nổi bật, tham khảo code sau và áp dụng phong cách mới:

<!DOCTYPE html>
<html lang="vi">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Kho Apple ID Tết 2026 - CSA Group</title>
    <!-- Favicon -->
    <link rel="shortcut icon" href="https://thongtin.yuichycsa.id.vn/image/logo.png" type="image/png" />

    <!-- FontAwesome for Icons -->
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css" />
    <style>
        /* ==== GLOBAL RESET & THEME TET 2026 ==== */
        :root {
            /* Theme Tết 2026: Đỏ Nhung & Vàng Kim */
            --csa-bg-color: #800000; /* Màu nền chủ đạo đỏ đậm */
            --csa-panel: rgba(100, 0, 0, 0.6); 
            --csa-border: rgba(255, 215, 0, 0.5); 
            --csa-text: #ffffff;
            --csa-muted: #ffeaa7; 
            --csa-red: #d63031;     
            --csa-green: #00b894;   
            --csa-gold: #FFD700;    
            --csa-radius: 16px;
            --csa-font: system-ui, -apple-system, sans-serif;
        }

        body {
            margin: 0; padding: 0;
            font-family: var(--csa-font);
            color: var(--csa-text);
            min-height: 100vh;
            display: flex; flex-direction: column; align-items: center;
            overflow-x: hidden;

            /* NỀN MỚI: Họa tiết lưới vàng trên nền đỏ nhung */
            background-color: var(--csa-bg-color);
            background-image: 
                radial-gradient(circle at 50% 0%, #d10000 0%, transparent 60%), /* Ánh sáng từ trên */
                repeating-linear-gradient(45deg, rgba(255, 215, 0, 0.05) 0px, rgba(255, 215, 0, 0.05) 1px, transparent 1px, transparent 10px),
                repeating-linear-gradient(-45deg, rgba(255, 215, 0, 0.05) 0px, rgba(255, 215, 0, 0.05) 1px, transparent 1px, transparent 10px);
            background-attachment: fixed;
        }

        .page-container {
            width: 100%; max-width: 1000px; padding: 20px;
            box-sizing: border-box; position: relative; z-index: 10;
        }

        a { color: var(--csa-gold); text-decoration: none; font-weight: 600; }
        a:hover { color: #fff; text-decoration: underline; text-shadow: 0 0 5px var(--csa-gold); }
        * { box-sizing: border-box; }

        /* ==== DECORATION: LỒNG ĐÈN (LANTERNS) ==== */
        .lantern-container {
            position: fixed; top: -20px; z-index: 5; pointer-events: none;
            display: flex; justify-content: center;
        }
        .lantern-left { left: 5%; }
        .lantern-right { right: 5%; }

        .lantern {
            position: relative; width: 80px; height: 100px;
            background: radial-gradient(circle, #ff5e62, #ff0000);
            border-radius: 40px;
            box-shadow: 0 5px 25px rgba(255, 0, 0, 0.5);
            animation: swing 3s infinite ease-in-out;
            transform-origin: top center;
        }
        .lantern::before { /* Dây treo */
            content: ''; position: absolute; top: -30px; left: 50%; transform: translateX(-50%);
            width: 4px; height: 30px; background: #b71540;
        }
        .lantern::after { /* Đuôi đèn */
            content: ''; position: absolute; bottom: -20px; left: 50%; transform: translateX(-50%);
            width: 6px; height: 20px; background: #ffd700;
            box-shadow: 0 5px 10px rgba(255, 215, 0, 0.5);
        }
        .lantern-text {
            position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%);
            font-size: 24px; font-weight: bold; color: #ffd700;
        }
        @keyframes swing { 0%,100%{transform:rotate(-6deg)} 50%{transform:rotate(6deg)} }

        /* ==== NEW: COUNTDOWN TIMER ==== */
        .countdown-box {
            display: flex; justify-content: center; gap: 15px;
            margin: -10px 0 30px 0;
        }
        .cd-item {
            background: linear-gradient(to bottom, #b71540, #000);
            border: 1px solid var(--csa-gold);
            padding: 10px; border-radius: 8px; min-width: 60px; text-align: center;
            box-shadow: 0 0 10px rgba(255,215,0,0.3);
        }
        .cd-num { font-size: 20px; font-weight: bold; color: var(--csa-gold); display: block; font-family: monospace; }
        .cd-label { font-size: 10px; color: #fff; text-transform: uppercase; }

        /* ==== NEW: RUNNING HORSE ANIMATION (UPDATED) ==== */
        .horse-track {
            position: fixed; bottom: 0; left: 0; width: 100%; height: 60px;
            pointer-events: none; z-index: 4; overflow: hidden;
        }
        .running-horse {
            position: absolute; bottom: 10px;
            color: var(--csa-gold);
            font-size: 35px;
            white-space: nowrap; /* Để ngựa xếp hàng ngang */
            transition: left 10s linear; /* Dùng transition thay vì animation */
            width: max-content;
            filter: drop-shadow(0 0 10px rgba(255,215,0,0.8));
            will-change: left;
            left: -200px; /* Khởi tạo ẩn bên trái */
        }

        /* ==== NEW: GOLD TEXT SHIMMER ==== */
        .gold-shimmer {
            background: linear-gradient(to right, #bf953f, #fcf6ba, #b38728, #fbf5b7, #aa771c);
            -webkit-background-clip: text;
            background-clip: text;
            color: transparent;
            background-size: 200%;
            animation: shine 3s infinite linear;
        }
        @keyframes shine { to { background-position: 200% center; } }

        /* ==== NOTIFICATION BOX ==== */
        .csa-notif-box {
            background: rgba(255, 215, 0, 0.15);
            border: 2px solid var(--csa-gold);
            border-radius: 16px;
            padding: 20px;
            margin-bottom: 24px;
            display: flex;
            align-items: flex-start;
            gap: 16px;
            box-shadow: 0 0 20px rgba(255, 215, 0, 0.2);
            animation: pulse-gold 3s infinite;
        }
        @keyframes pulse-gold {
            0% { box-shadow: 0 0 0 0 rgba(255, 215, 0, 0.4); }
            70% { box-shadow: 0 0 0 8px rgba(255, 215, 0, 0); }
            100% { box-shadow: 0 0 0 0 rgba(255, 215, 0, 0); }
        }
        .notif-icon {
            font-size: 30px;
            background: var(--csa-gold);
            color: #b30000;
            width: 50px; height: 50px;
            border-radius: 50%;
            display: grid; place-items: center;
            flex-shrink: 0;
        }
        .notif-content h3 {
            margin: 0 0 8px 0;
            color: var(--csa-gold);
            text-transform: uppercase;
            font-size: 16px;
            border-bottom: 1px dashed rgba(255,255,255,0.3);
            padding-bottom: 5px;
            display: inline-block;
        }
        .notif-content p {
            margin: 0;
            color: #fff;
            line-height: 1.5;
            font-size: 15px;
        }

        /* ==== EFFECT LAYERS ==== */
        #fireworksCanvas {
            position: fixed; top: 0; left: 0; width: 100%; height: 100%;
            pointer-events: none; z-index: 1;
        }
        .falling-container {
            position: fixed; top: 0; left: 0; width: 100%; height: 100%;
            pointer-events: none; z-index: 2; overflow: hidden;
        }
        .falling-item {
            position: absolute; top: -50px;
            animation: fall linear forwards;
            font-size: 20px;
        }
        @keyframes fall { to { transform: translateY(110vh) rotate(360deg); } }

        /* Header */
        .csa-header { 
            display: flex; align-items: center; gap: 16px; 
            margin-bottom: 24px; padding-bottom: 20px;
            border-bottom: 2px solid var(--csa-border);
            position: relative; margin-top: 20px; 
        }
        .csa-logo { 
            width: 64px; height: 64px; 
            background: linear-gradient(135deg, #b71540, #000); 
            border-radius: 50%; display: grid; place-items: center; 
            font-size: 32px; box-shadow: 0 0 25px rgba(255, 215, 0, 0.7);
            border: 2px solid var(--csa-gold); position: relative;
        }
        .csa-hat { 
            position: absolute; top: -12px; right: -8px; 
            font-size: 28px; transform: rotate(15deg); 
        }
        .csa-title h1 { 
            margin: 0; font-size: 26px; 
            text-transform: uppercase; 
            letter-spacing: 1px;
        }
        .csa-title p { margin: 6px 0 0; font-size: 14px; color: var(--csa-muted); }

        /* Alert */
        .csa-alert {
            background: rgba(139, 0, 0, 0.7); 
            border: 2px solid #ff4757;
            padding: 16px; border-radius: var(--csa-radius); 
            display: flex; gap: 14px; margin-bottom: 30px; 
            font-size: 15px; line-height: 1.5; color: #fff;
            box-shadow: 0 0 15px rgba(255, 71, 87, 0.3);
            animation: pulse-border 2s infinite;
        }
        @keyframes pulse-border {
            0% { box-shadow: 0 0 0 0 rgba(255, 71, 87, 0.6); }
            70% { box-shadow: 0 0 0 8px rgba(255, 71, 87, 0); }
            100% { box-shadow: 0 0 0 0 rgba(255, 71, 87, 0); }
        }

        /* ACCOUNT GRID */
        .api-container {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
            gap: 20px; margin-bottom: 30px; width: 100%;
        }

        .csa-acc-card {
            background: rgba(50, 0, 0, 0.6); 
            border: 1px solid var(--csa-border);
            border-radius: 18px; overflow: hidden;
            backdrop-filter: blur(8px);
            transition: transform 0.3s ease, box-shadow 0.3s ease;
            display: flex; flex-direction: column;
            position: relative;
        }
        /* Góc trang trí thẻ */
        .csa-acc-card::before {
            content: ''; position: absolute; top: 0; left: 0; 
            width: 40px; height: 40px; 
            background: linear-gradient(135deg, var(--csa-gold) 50%, transparent 50%);
            opacity: 0.8; pointer-events: none; z-index: 2;
        }

        .csa-acc-card:hover { 
            transform: translateY(-5px); 
            border-color: #fff; 
            box-shadow: 0 10px 30px rgba(255, 215, 0, 0.4);
        }

        /* Banner Ảnh */
        .csa-acc-thumb {
            width: 100%; aspect-ratio: 16/9; background: #300;
            overflow: hidden; border-bottom: 2px solid rgba(255,215,0,0.5);
            position: relative; cursor: zoom-in;
        }
        .csa-acc-thumb img { width: 100%; height: 100%; object-fit: contain; object-position: center; transition: transform 0.5s; }
        .csa-acc-card:hover .csa-acc-thumb img { transform: scale(1.05); }

        .csa-zoom-hint {
            position: absolute; inset: 0; background: rgba(0,0,0,0.4);
            display: flex; align-items: center; justify-content: center;
            opacity: 0; transition: opacity 0.3s; color: var(--csa-gold); font-size: 28px;
            backdrop-filter: blur(2px);
        }
        .csa-acc-thumb:hover .csa-zoom-hint { opacity: 1; }

        .csa-acc-header {
            background: linear-gradient(90deg, #c0392b, #d35400);
            padding: 10px 16px; color: #fff; font-weight: 700; font-size: 13px;
            display: flex; justify-content: space-between; align-items: center;
            border-bottom: 1px solid rgba(255,255,255,0.2);
        }
        .csa-acc-header.alt { background: linear-gradient(90deg, #16a085, #27ae60); }

        .csa-acc-body { padding: 16px; }

        .csa-field { margin-bottom: 12px; }
        .csa-label { font-size: 11px; text-transform: uppercase; color: var(--csa-muted); margin-bottom: 4px; display: block; font-weight: 600; }

        .csa-input-wrap {
            display: flex; align-items: center;
            background: rgba(0, 0, 0, 0.4); border: 1px solid var(--csa-border);
            border-radius: 10px; cursor: pointer; transition: 0.2s;
        }
        .csa-input-wrap:hover { border-color: #fff; background: rgba(255,215,0,0.2); }
        .csa-input-wrap:active { transform: scale(0.98); }

        .csa-value {
            flex: 1; padding: 10px 12px; font-family: monospace; font-size: 14px;
            color: var(--csa-gold); white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
            font-weight: bold;
        }
        .csa-copy-icon { padding: 0 12px; color: var(--csa-green); font-size: 16px; }

        .csa-meta {
            margin-top: 14px; padding-top: 12px; border-top: 1px solid rgba(255,215,0,0.3);
            display: flex; justify-content: space-between; font-size: 11px; color: var(--csa-muted);
        }
        .status-dot { width: 8px; height: 8px; border-radius: 50%; display: inline-block; margin-right: 6px; }
        .st-true { background: var(--csa-green); box-shadow: 0 0 8px var(--csa-green); }
        .st-false { background: var(--csa-red); }

        .csa-empty { grid-column: 1 / -1; text-align: center; padding: 40px; background: rgba(0,0,0,0.3); border-radius: 16px; border: 2px dashed var(--csa-gold); }

        /* CUSTOM TOAST NOTIFICATION */
        .csa-toast {
            position: fixed; top: 24px; right: 24px; z-index: 10000;
            background: rgba(183, 21, 64, 0.95);
            border: 2px solid var(--csa-gold);
            border-radius: 12px;
            padding: 16px 20px;
            display: flex; align-items: center; gap: 12px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            transform: translateX(120%); transition: transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
            backdrop-filter: blur(10px);
        }
        .csa-toast.show { transform: translateX(0); }
        .csa-toast-icon { 
            width: 24px; height: 24px; background: var(--csa-gold); color: #8E0E00;
            border-radius: 50%; display: grid; place-items: center; font-size: 14px; font-weight: bold;
        }
        .csa-toast-msg { font-size: 14px; font-weight: 500; color: #fff; }

        /* LIGHTBOX */
        .csa-lightbox {
            position: fixed; inset: 0; background: rgba(0,0,0,0.95); z-index: 10000;
            display: none; justify-content: center; align-items: center; 
            opacity: 0; transition: opacity 0.3s;
        }
        .csa-lightbox.active { display: flex; opacity: 1; }
        .csa-lightbox img { 
            max-width: 90vw; max-height: 90vh; border-radius: 8px; 
            box-shadow: 0 0 30px rgba(255,215,0,0.6); transform: scale(0.9); transition: transform 0.3s;
            border: 4px solid var(--csa-gold);
        }
        .csa-lightbox.active img { transform: scale(1); }
        .csa-lightbox-close {
            position: absolute; top: 20px; right: 20px; color: var(--csa-gold); font-size: 30px; cursor: pointer;
            width: 40px; height: 40px; background: rgba(255,255,255,0.1); border-radius: 50%;
            display: grid; place-items: center; transition: 0.2s;
            border: 1px solid var(--csa-gold);
        }
        .csa-lightbox-close:hover { background: rgba(255,215,0,0.3); }

        /* Badges & Instructions */
        .csa-badges { display: flex; flex-wrap: wrap; gap: 10px; margin-bottom: 30px; justify-content: center; }
        .csa-badge {
            font-size: 13px; padding: 8px 16px; border-radius: 30px; font-weight: 600;
            border: 1px solid var(--csa-gold); background: rgba(100,0,0,0.5); color: var(--csa-gold);
            box-shadow: 0 0 10px rgba(255,215,0,0.2);
        }

        /* Grid Layout */
        .csa-grid-content { display: grid; gap: 20px; }
        @media (min-width: 900px) { .csa-grid-content { grid-template-columns: 1fr 1fr; } }

        .csa-box { background: var(--csa-panel); border: 1px solid var(--csa-border); border-radius: var(--csa-radius); padding: 24px; display: flex; flex-direction: column; }
        .csa-list { margin: 0; padding-left: 24px; line-height: 1.6; font-size: 15px; color: var(--csa-muted); }
        .csa-list li { margin-bottom: 12px; }
        .csa-list strong { color: var(--csa-gold); }

        .status-box { padding: 16px; border-radius: 12px; margin-bottom: 16px; background: rgba(0,0,0,0.3); border: 1px solid rgba(255,255,255,0.1); }
        .status-ok { border-left: 4px solid var(--csa-green); }
        .status-no { border-left: 4px solid var(--csa-red); }
        .csa-footer { margin-top: 40px; text-align: center; font-size: 13px; color: var(--csa-muted); padding-bottom: 20px; opacity: 0.7; }

        /* Social Buttons */
        .social-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
        .csa-btn-social {
            display: flex; align-items: center; justify-content: center; gap: 8px;
            padding: 12px; border-radius: 12px; font-weight: 600; font-size: 13px;
            text-decoration: none; transition: 0.2s; white-space: nowrap;
        }
        .btn-tele { background: rgba(34, 158, 217, 0.2); color: #4db8ff; border: 1px solid rgba(34, 158, 217, 0.4); }
        .btn-tele:hover { background: rgba(34, 158, 217, 0.3); transform: translateY(-2px); border-color: #4db8ff; }

        .btn-fb { background: rgba(24, 119, 242, 0.2); color: #5af; border: 1px solid rgba(24, 119, 242, 0.4); }
        .btn-fb:hover { background: rgba(24, 119, 242, 0.3); transform: translateY(-2px); border-color: #5af; }

        /* Music & Effect Toggles (Fixed Bottom) */
        .csa-controls {
            position: fixed; bottom: 20px; right: 20px; z-index: 9000;
            display: flex; flex-direction: column; gap: 10px;
        }
        .csa-ctrl-btn {
            width: 50px; height: 50px; background: rgba(180, 0, 0, 0.8);
            border-radius: 50%; display: grid; place-items: center;
            cursor: pointer; border: 2px solid var(--csa-gold); transition: 0.2s;
            color: var(--csa-gold); box-shadow: 0 0 15px rgba(255, 215, 0, 0.4);
            font-size: 20px;
        }
        .csa-ctrl-btn:hover { background: rgba(255, 215, 0, 0.2); transform: scale(1.1); }
        .csa-ctrl-btn.playing { border-color: var(--csa-green); color: var(--csa-green); animation: spin-slow 8s linear infinite; }
        .csa-ctrl-btn.off { filter: grayscale(1); opacity: 0.7; border-color: #ccc; color: #ccc; }

        @keyframes spin-slow { 100% { transform: rotate(360deg); } }

        /* Hidden YouTube Player */
        #youtube-audio { display: none; }
    </style>
</head>
<body>

    <!-- Lồng Đèn Trang Trí (CSS Only) -->
    <div class="lantern-container lantern-left">
        <div class="lantern"><div class="lantern-text">Tết</div></div>
    </div>
    <div class="lantern-container lantern-right">
        <div class="lantern"><div class="lantern-text">2026</div></div>
    </div>

    <!-- Ngựa Vàng Chạy (Marquee Effect) -->
    <div class="horse-track" id="horseTrack">
        <div class="running-horse"><i class="fa-solid fa-horse-head"></i></div>
    </div>

    <!-- Hidden YouTube Player Container -->
    <div id="youtube-audio"></div>

    <!-- CONTROLS: Music & Effects -->
    <div class="csa-controls">
        <div class="csa-ctrl-btn" id="effectBtn" onclick="toggleEffects()" title="Bật/Tắt Hiệu ứng">
            <i class="fa-solid fa-wand-magic-sparkles"></i>
        </div>
        <div class="csa-ctrl-btn" id="musicBtn" onclick="toggleMusic()" title="Bật/Tắt Nhạc">
            <i class="fa-solid fa-music"></i>
        </div>
    </div>

    <!-- Layers Hiệu ứng (Tự động chạy) -->
    <canvas id="fireworksCanvas"></canvas>
    <div class="falling-container" id="fallingContainer"></div>

    <!-- Custom Toast Notification -->
    <div id="csaToast" class="csa-toast">
        <div class="csa-toast-icon">✓</div>
        <div class="csa-toast-msg">Đã sao chép thành công!</div>
    </div>

    <!-- Lightbox Modal -->
    <div id="csaLightbox" class="csa-lightbox">
        <div class="csa-lightbox-close" onclick="closeLightbox()">&times;</div>
        <img id="csaLightboxImg" src="" alt="Zoomed Image">
    </div>

    <div class="page-container">

        <!-- Header -->
        <header class="csa-header">
            <div class="csa-logo">
                <img src="https://thongtin.yuichycsa.id.vn/image/logo.png" alt="Logo" style="width:100%; height:100%; border-radius:50%; opacity: 1;">
                <span class="csa-hat">🐎</span> <!-- Năm 2026 là Ngựa (Bính Ngọ) -->
            </div>
            <div class="csa-title">
                <h1 class="gold-shimmer">Kho Apple ID Tết 2026</h1>
                <p>Xuân Bính Ngọ - Mã Đáo Thành Công - CSA Group</p>
            </div>
        </header>

        <!-- Countdown Timer -->
        <div class="countdown-box" id="csaCountdown">
            <div class="cd-item"><span class="cd-num" id="cd-days">00</span><span class="cd-label">Ngày</span></div>
            <div class="cd-item"><span class="cd-num" id="cd-hours">00</span><span class="cd-label">Giờ</span></div>
            <div class="cd-item"><span class="cd-num" id="cd-minutes">00</span><span class="cd-label">Phút</span></div>
            <div class="cd-item"><span class="cd-num" id="cd-seconds">00</span><span class="cd-label">Giây</span></div>
        </div>

        <!-- Notification Box (NEW FEATURE) -->
                <div class="csa-notif-box">
            <div class="notif-icon"><i class="fa-solid fa-bell"></i></div>
            <div class="notif-content">
                <h3>🔔 Thông báo</h3>
                <!-- Cho phép render HTML để dùng thẻ <b> <i> <br> -->
                <p><b>ĐÓNG ID APPLE VÌ LÝ DO BỊ PHÁ HOẠI</b> <i class="fa-solid fa-triangle-exclamation"></i><br>XIN CẢM ƠN CÁC BẠN ICLOUD ĐÃ THOÁT FAMILY TẢI APP CỦA ID.<br>SAU ĐỨA NÀO LOGIN THÌ CHO BAY MÁY NGAY LẬP TỨC, MẸ HIỀN KHÔNG KHÓA MÁY THÌ CHÚNG MÀY PHÁ ID THẾ À</p>
            </div>
        </div>

        <!-- Warning -->
        <div class="csa-alert">
            <div style="font-size: 24px;">🧧</div>
            <div>
                <strong>LÌ XÌ ĐẦU NĂM - LƯU Ý KỸ:</strong><br>
                Chỉ đăng nhập tài khoản tại <strong>App Store</strong> để tải game. <br>
                Tuyệt đối <strong>KHÔNG</strong> đăng nhập vào iCloud (Cài đặt) để tránh bị khóa máy!
            </div>
        </div>

        <!-- PHP RENDERED ACCOUNTS -->
        <div class="api-container">
                            <div class="csa-empty">
                    <h3>📭 Hệ thống đang cập nhật dữ liệu mới...</h3>
                    <p style="color:var(--csa-muted)">Hệ thống đang cập nhật lì xì mới...</p>
                </div>
                    </div>

        <!-- Badges -->
        <div class="csa-badges">
