        // Lấy cấu hình từ PHP truyền xuống JS
        var youtubeID = "LjeDW43A3xw";

        // --- CORE LOGIC START ---

        // 1. Kích hoạt hiệu ứng ngay lập tức
        window.addEventListener('load', function() {
            startFallingEffect();
            startFireworks();
            startCountdown();
            initHorseRun(); // Kích hoạt đàn ngựa
        });

        // 2. Countdown Logic
        function startCountdown() {
            // Ngày Tết Nguyên Đán 2026 (17/02/2026)
            const countTo = new Date('Feb 17, 2026 00:00:00').getTime();
            const elements = {
                d: document.getElementById('cd-days'),
                h: document.getElementById('cd-hours'),
                m: document.getElementById('cd-minutes'),
                s: document.getElementById('cd-seconds')
            };

            setInterval(() => {
                const now = new Date().getTime();
                const gap = countTo - now;

                if (gap < 0) {
                    return;
                }

                const d = Math.floor(gap / (1000 * 60 * 60 * 24));
                const h = Math.floor((gap % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
                const m = Math.floor((gap % (1000 * 60 * 60)) / (1000 * 60));
                const s = Math.floor((gap % (1000 * 60)) / 1000);

                elements.d.innerText = d < 10 ? '0' + d : d;
                elements.h.innerText = h < 10 ? '0' + h : h;
                elements.m.innerText = m < 10 ? '0' + m : m;
                elements.s.innerText = s < 10 ? '0' + s : s;
            }, 1000);
        }

        // 3. Toast Logic & RANDOM WISHES
        let toastTimeout;
        const toast = document.getElementById('csaToast');
