        var isUserPaused = false; // Biến kiểm soát việc người dùng chủ động tắt nhạc

        function onYouTubeIframeAPIReady() {
            player = new YT.Player('youtube-audio', {
                height: '0', width: '0',
                videoId: youtubeID,
