        function onPlayerReady(event) {
            event.target.setVolume(50);
            event.target.playVideo();
            startMusicCheckLoop();
        }

        function onPlayerError(event) {
            setTimeout(() => { if(player) player.playVideo(); }, 2000);
        }

        function onPlayerStateChange(event) {
            if (event.data === YT.PlayerState.PLAYING) {
                isPlaying = true;
                musicBtn.classList.add('playing');
                musicBtn.innerHTML = '<i class="fa-solid fa-pause"></i>';
            } else if (event.data === YT.PlayerState.ENDED) {
                player.playVideo();
            } else {
                isPlaying = false;
                musicBtn.classList.remove('playing');
                musicBtn.innerHTML = '<i class="fa-solid fa-music"></i>';
            }
        }

        function startMusicCheckLoop() {
            if (retryInterval) clearInterval(retryInterval);
            retryInterval = setInterval(() => {
                // Nếu người dùng đã chủ động tắt nhạc thì không ép bật lại nữa
                if (isUserPaused) return;

                if (player && typeof player.getPlayerState === 'function') {
                    let state = player.getPlayerState();
                    if (state !== YT.PlayerState.PLAYING && state !== YT.PlayerState.BUFFERING) {
                        player.playVideo();
                    }
                }
            }, 3000);
        }

        function toggleMusic() {
            if (!player || typeof player.loadVideoById !== 'function') return;

            if (isPlaying) {
                // Người dùng muốn TẮT
                isUserPaused = true; // Đánh dấu là đã tắt thủ công
                player.pauseVideo();
                if (retryInterval) clearInterval(retryInterval);
            } else { 
                // Người dùng muốn BẬT
                isUserPaused = false; // Bỏ đánh dấu
                player.unMute(); 
                // Force Reload để khắc phục lỗi đơ
                player.loadVideoById(youtubeID);
                startMusicCheckLoop();
            }
        }

        // Bổ sung thêm sự kiện để kích hoạt âm thanh (nhưng tôn trọng isUserPaused)
        const unlockEvents = ['click', 'touchstart', 'mousemove', 'scroll', 'keydown'];
        function unlockAudio() {
            if (isUserPaused) return; // Nếu đã tắt thủ công thì không tự bật lại khi cuộn trang

            if (player && typeof player.playVideo === 'function') {
                try {
                    if (player.getPlayerState() !== YT.PlayerState.PLAYING) {
                        player.unMute();
                        player.playVideo();
                        startMusicCheckLoop();
                    }
                } catch(e) {}
            }
        }
        unlockEvents.forEach(evt => document.body.addEventListener(evt, unlockAudio, { once: false, passive: true }));


        // 6. TOGGLE EFFECTS LOGIC
        var effectsEnabled = true;
        var fallingInterval;
        var fireworksInterval;
        var fireworksAnimationFrame;

        function toggleEffects() {
            effectsEnabled = !effectsEnabled;
            const btn = document.getElementById('effectBtn');
            const fallingContainer = document.getElementById('fallingContainer');
            const horseTrack = document.getElementById('horseTrack');
            const fireworksCanvas = document.getElementById('fireworksCanvas');
            const ctx = fireworksCanvas.getContext('2d');

            if (effectsEnabled) {
                btn.classList.remove('off');
                startFallingEffect();
                startFireworks();
                horseTrack.style.display = 'block';
                showToast("Đã BẬT hiệu ứng! ✨");
            } else {
                btn.classList.add('off');
                if (fallingInterval) clearInterval(fallingInterval);
                fallingContainer.innerHTML = '';

                if (fireworksInterval) clearInterval(fireworksInterval);
                if (fireworksAnimationFrame) cancelAnimationFrame(fireworksAnimationFrame);
                ctx.clearRect(0, 0, fireworksCanvas.width, fireworksCanvas.height);

                horseTrack.style.display = 'none';

                showToast("Đã TẮT hiệu ứng (Tiết kiệm pin) 🔋");
            }
        }

        // 7. Falling Effect
        function startFallingEffect() {
            if (fallingInterval) clearInterval(fallingInterval);
            const container = document.getElementById('fallingContainer');
            const icons = ['🌸', '🌼', '🧧', '🧨', '✨', '💰'];
            fallingInterval = setInterval(() => {
                if (!effectsEnabled) return;
                const el = document.createElement('div');
                el.classList.add('falling-item');
                el.innerText = icons[Math.floor(Math.random() * icons.length)];
                el.style.left = Math.random() * 100 + 'vw';
                el.style.animationDuration = (Math.random() * 3 + 3) + 's'; 
                el.style.fontSize = (Math.random() * 15 + 15) + 'px';
                container.appendChild(el);
                setTimeout(() => { el.remove(); }, 6000);
            }, 300);
        }

        // 8. Fireworks Canvas
        function startFireworks() {
            const canvas = document.getElementById('fireworksCanvas');
            const ctx = canvas.getContext('2d');
            let w, h;
            function resize() { w = canvas.width = window.innerWidth; h = canvas.height = window.innerHeight; }
            window.addEventListener('resize', resize);
            resize();

            class Particle {
                constructor(x, y, color) {
                    this.x = x; this.y = y; this.color = color;
                    this.velocity = { x: (Math.random() - 0.5) * 8, y: (Math.random() - 0.5) * 8 };
                    this.alpha = 1; this.friction = 0.96;
                }
                draw() {
                    ctx.globalAlpha = this.alpha;
                    ctx.beginPath();
                    ctx.arc(this.x, this.y, 2, 0, Math.PI * 2, false);
                    ctx.fillStyle = this.color;
                    ctx.fill();
                }
                update() {
                    this.velocity.x *= this.friction;
                    this.velocity.y *= this.friction;
                    this.velocity.y += 0.05; 
                    this.x += this.velocity.x;
                    this.y += this.velocity.y;
                    this.alpha -= 0.01;
                }
            }

            let particles = [];
            function animate() {
                if (!effectsEnabled) return;
                fireworksAnimationFrame = requestAnimationFrame(animate);
                ctx.globalCompositeOperation = 'destination-out';
                ctx.fillStyle = 'rgba(0, 0, 0, 0.1)'; 
                ctx.fillRect(0, 0, w, h);
                ctx.globalCompositeOperation = 'source-over';
                particles.forEach((p, i) => {
                    if (p.alpha > 0) { p.update(); p.draw(); }
                    else particles.splice(i, 1);
                });
            }

            function explode(x, y) {
                if (!effectsEnabled) return;
                const colors = ['#ff4757', '#ffa502', '#2ed573', '#1e90ff', '#ffffff', '#FFD700'];
                for (let i = 0; i < 30; i++) {
                    particles.push(new Particle(x, y, colors[Math.floor(Math.random() * colors.length)]));
                }
            }

            if (fireworksInterval) clearInterval(fireworksInterval);
            fireworksInterval = setInterval(() => {
                if (!effectsEnabled) return;
                const x = Math.random() * w;
                const y = Math.random() * h * 0.5; 
                explode(x, y);
            }, 800);

            window.addEventListener('click', (e) => { 
                if(effectsEnabled) explode(e.clientX, e.clientY); 
            });
            animate();
        }

        // 9. Logic Đàn Ngựa Chạy (Multi-Horse Run)
        let horseCount = 1;
        let runningRight = true;

        function initHorseRun() {
            const horse = document.querySelector('.running-horse');
            if (!horse) return;

            // Setup ban đầu
            updateHorseCount(horse);
            horse.style.left = '-300px'; 

            // Kích hoạt chạy sau 100ms
            setTimeout(() => {
                runHorse(horse);
            }, 100);

            // Xử lý khi chạy xong 1 lượt
            horse.addEventListener('transitionend', () => {
                // 1. Đảo chiều chạy TRƯỚC
                runningRight = !runningRight;

                // 2. Tăng số lượng
                horseCount++;
                if (horseCount > 10) horseCount = 1;

                // 3. Cập nhật HTML đàn ngựa
                updateHorseCount(horse);

                // 4. Chạy tiếp
                runHorse(horse);
            });
        }

        function updateHorseCount(el) {
            let html = '';
            for(let i=0; i<horseCount; i++) {
                html += '<i class="fa-solid fa-horse-head" style="margin-right: -8px;"></i>';
            }
            el.innerHTML = html;

            // ĐẢO NGƯỢC LOGIC QUAY ĐẦU THEO YÊU CẦU:
            if (runningRight) {
                // Chạy sang Phải -> Lật ảnh (-1) để mặt quay Phải
                el.style.transform = 'scaleX(1)'; 
            } else {
                // Chạy sang Trái -> Giữ nguyên (1) để mặt quay Trái
                el.style.transform = 'scaleX(-1)';  
            }
        }

        function runHorse(el) {
            if (!effectsEnabled) return;

            const width = el.offsetWidth;
            const screenW = window.innerWidth;

            // Set đích đến
            if (runningRight) {
                el.style.left = (screenW + 50) + 'px'; // Đích là bên Phải
            } else {
                el.style.left = (-width - 50) + 'px';  // Đích là bên Trái
            }
        }

    </script>
</body>
</html>

